import React, { useState, useEffect } from 'react';
import { View, Text, TextInput, Button, AsyncStorage } from 'react-native';

const AuthScreen = ({ onAuthSuccess }) => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');

  const handleLogin = async () => {
    // Simulate API request
    const fakeToken = '12345';
    const userData = { email };
    await AsyncStorage.setItem('authToken', fakeToken);
    await AsyncStorage.setItem('userData', JSON.stringify(userData));
    onAuthSuccess(userData);
  };

  return (
    <View>
      <Text>Login</Text>
      <TextInput value={email} onChangeText={setEmail} placeholder="Email" />
      <TextInput
        value={password}
        onChangeText={setPassword}
        placeholder="Password"
        secureTextEntry
      />
      <Button title="Login" onPress={handleLogin} />
    </View>
  );
};

const HomeScreen = ({ user }) => (
  <View>
    <Text>Welcome, {user.email}</Text>
  </View>
);

export default function App() {
  const [authState, setAuthState] = useState({ loggedIn: false, user: null });

  useEffect(() => {
    const checkLoginStatus = async () => {
      try {
        const token = await AsyncStorage.getItem('authToken');
        const userData = await AsyncStorage.getItem('userData');
        if (token && userData) {
          setAuthState({ loggedIn: true, user: JSON.parse(userData) });
        }
      } catch (error) {
        console.log('Error fetching data:', error);
      }
    };
    checkLoginStatus();
  }, []);

  if (authState.loggedIn) {
    return <HomeScreen user={authState.user} />;
  }

  return <AuthScreen onAuthSuccess={(user) => setAuthState({ loggedIn: true, user })} />;
}